        qw.lambda()
                .eq(SpaceNodeTagRelEntity::getTagId, tagId)
                .eq(SpaceNodeTagRelEntity::getUserId, userId)
                .select(SpaceNodeTagRelEntity::getSpaceNodeId);
        return list(qw).stream().map(SpaceNodeTagRelEntity::getSpaceNodeId).toList();
    }
}

